montant_actifs,\n    pc.montant_passifs,\n    pc.position_nette,\n    pc.taux_change,\n    pc.position_nette_tnd,\n    pc.date_valeur\nFROM position_change pc\nWHERE pc.date_valeur BETWEEN :dateDebut AND :dateFin\nORDER BY pc.date_valeur, pc.devise_code','declaration_risques_change_taux.xsd',NULL),(3,'D├®claration Mensuelle des Risques de Change et de Taux','<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"no\"?>\r\n<Declaration code=\"BCT_01\" dateDebut=\"2025-01-01\" dateFin=\"2025-01-31\" nombreLignes=\"15\" periode=\"2025-01\">\r\n  <Entete>\r\n    <CodeDeclaration>BCT_01</CodeDeclaration>\r\n    <Periode>2025-01</Periode>\r\n    <DateDebut>2025-01-01</DateDebut>\r\n    <DateFin>2025-01-31</DateFin>\r\n    <NombreLignes>15</NombreLignes>\r\n    <DateGeneration>2026-03-10T15:07:06.548979200</DateGeneration>\r\n  </Entete>\r\n  <Donnees>\r\n    <Ligne>\r\n      <devise_code>CHF</devise_code>\r\n      <devise_libelle>Franc Suisse</devise_libelle>\r\n      <type_position>NULLE</type_position>\r\n      <montant_actifs>1500000.00</montant_actifs>\r\n      <montant_passifs>1500000.00</montant_passifs>\r\n      <position_nette>0.00</position_nette>\r\n      <taux_change>3.5100</taux_change>\r\n      <position_nette_tnd>0.00</position_nette_tnd>\r\n      <date_valeur>2025-01-05</date_valeur>\r\n    </Ligne>\r\n    <Ligne>\r\n      <devise_code>EUR</devise_code>\r\n      <devise_libelle>Euro</devise_libelle>\r\n      <type_position>LONGUE</type_position>\r\n      <montant_actifs>8750000.00</montant_actifs>\r\n      <montant_passifs>4200000.00</montant_passifs>\r\n      <position_nette>4550000.00</position_nette>\r\n      <taux_change>3.3800</taux_change>\r\n      <position_nette_tnd>15379000.00</position_nette_tnd>\r\n      <date_valeur>2025-01-05</date_valeur>\r\n    </Ligne>\r\n    <Ligne>\r\n      <devise_code>GBP</devise_code>\r\n      <devise_libelle>Livre Sterling</devise_libelle>\r\n      <type_position>COURTE</type_position>\r\n      <montant_actifs>1200000.0