INSERT INTO `declaration_templates` VALUES (1,'<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<DeclarationRisques xmlns=\"http://bct.tn/risques/v1\">\n  <Entete>\n    <CodeEtablissement>{CODE_ETABLISSEMENT}</CodeEtablissement>\n    <NomEtablissement>{NOM_ETABLISSEMENT}</NomEtablissement>\n    <PeriodeReference>{PERIODE_REFERENCE}</PeriodeReference>\n    <DateSoumission>{DATE_SOUMISSION}</DateSoumission>\n    <VersionDeclaration>1.0</VersionDeclaration>\n  </Entete>\n  \n  <RisquesChange>\n    <PositionGlobale>\n      <MontantTotal devise=\"TND\">{RISQUE_CHANGE_TOTAL}</MontantTotal>\n      <LimiteReglementaire>{LIMITE_CHANGE}</LimiteReglementaire>\n      <TauxUtilisation>{TAUX_UTILISATION_CHANGE}</TauxUtilisation>\n    </PositionGlobale>\n    \n    <PositionsParDevise>\n      <Position>\n        <CodeDevise>{DEVISE_1}</CodeDevise>\n        <MontantActif>{ACTIF_DEVISE_1}</MontantActif>\n        <MontantPassif>{PASSIF_DEVISE_1}</MontantPassif>\n        <PositionNette>{POSITION_NETTE_1}</PositionNette>\n      </Position>\n      <Position>\n        <CodeDevise>{DEVISE_2}</CodeDevise>\n        <MontantActif>{ACTIF_DEVISE_2}</MontantActif>\n        <MontantPassif>{PASSIF_DEVISE_2}</MontantPassif>\n        <PositionNette>{POSITION_NETTE_2}</PositionNette>\n      </Position>\n    </PositionsParDevise>\n  </RisquesChange>\n  \n  <RisquesTaux>\n    <ExpositionGlobale>\n      <MontantTotal>{RISQUE_TAUX_TOTAL}</MontantTotal>\n      <DureeModifiee>{DUREE_MODIFIEE}</DureeModifiee>\n      <Sensibilite>{SENSIBILITE_TAUX}</Sensibilite>\n    </ExpositionGlobale>\n    \n    <ExpositionParMaturite>\n      <Tranche>\n        <Maturite>MOINS_3_MOIS</Maturite>\n        <MontantActif>{ACTIF_M3}</MontantActif>\n        <MontantPassif>{PASSIF_M3}</MontantPassif>\n        <Gap>{GAP_M3}</Gap>\n      </Tranche>\n      <Tranche>\n        <Maturite>3_A_12_MOIS</Maturite>\n        <MontantActif>{ACTIF_3_12}</MontantActif>\n        <MontantPassif>{PASSIF_3_12}</MontantPassif>\n        <Gap>{GAP_3_12}</Gap>\n      </Tranche>\n      <Tranche>\n        <Maturite>PLUS_12_MOIS</Maturite>\n        <MontantActif>{ACTIF_12_PLUS}</MontantActif>\n        <MontantPassif>{PASSIF_12_PLUS}</MontantPassif>\n        <Gap>{GAP_12_PLUS}</Gap>\n      </Tranche>\n    </ExpositionParMaturite>\n  </RisquesTaux>\n  \n  <InstrumentsCouverture>\n    <MontantTotalCouverture>{MONTANT_COUVERTURE}</MontantTotalCouverture>\n    <Instrument>\n      <Type>{TYPE_COUVERTURE_1}</Type>\n      <Montant>{MONTANT_COUVERTURE_1}</Montant>\n      <Contrepartie>{CONTREPARTIE_1}</Contrepartie>\n      <Echeance>{ECHEANCE_1}</Echeance>\n    </Instrument>\n  </InstrumentsCouverture>\n  \n  <Certification>\n    <ResponsableDeclaration>{RESPONSABLE_DECLARATION}</ResponsableDeclaration>\n    <FonctionResponsable>{FONCTION_RESPONSABLE}</FonctionResponsable>\n    <DateCertification>{DATE_CERTIFICATION}</DateCertification>\n    <SignatureElectronique>{SIGNATURE}</SignatureElectronique>\n  </Certification>\n</DeclarationRisques>','{\n  \"CODE_ETABLISSEMENT\": \"Code unique de l\'├®tablissement financier\",\n  \"NOM_ETABLISSEMENT\": \"Nom complet de l\'├®tablissement\",\n  \"PERIODE_REFERENCE\": \"P├®riode au format YYYY-MM\",\n  \"DATE_SOUMISSION\": \"Date de soumission au format YYYY-MM-DD\",\n  \"RISQUE_CHANGE_TOTAL\": \"Exposition totale au risque de change en TND\",\n  \"LIMITE_CHANGE\": \"Limite r├®glementaire de risque de change\",\n  \"TAUX_UTILISATION_CHANGE\": \"Pourcentage d\'utilisation de la limite\",\n  \"DEVISE_1\": \"Code devise ISO (EUR, USD, etc.)\",\n  \"ACTIF_DEVISE_1\": \"Montant des actifs dans cette devise\",\n  \"PASSIF_DEVISE_1\": \"Montant des passifs dans cette devise\",\n  \"POSITION_NETTE_1\": \"Position nette (Actif - Passif)\",\n  \"RISQUE_TAUX_TOTAL\": \"Exposition totale au risque de taux\",\n  \"DUREE_MODIFIEE\": \"Duration modifi├®e du portefeuille\",\n  \"SENSIBILITE_TAUX\": \"Sensibilit├® aux variations de taux\",\n  \"ACTIF_M3\": \"Actifs ├á ├®ch├®ance < 3 mois\",\n  \"PASSIF_M3\": \"Passifs ├á ├®ch├®ance < 3 mois\",\n  \"GAP_M3\": \"Gap de liquidit├® < 3 mois\",\n  \"MONTANT_COUVERTURE\": \"Montant total des instruments de couverture\",\n  \"TYPE_COUVERTURE_1\": \"Type d\'instrument (SWAP, FORWARD, OPTION)\",\n  \"MONTANT_COUVERTURE_1\": \"Montant nominal de la couverture\",\n  \"CONTREPARTIE_1\": \"Nom de la contrepartie\",\n  \"ECHEANCE_1\": \"Date d\'├®ch├®ance de l\'instrument\",\n  \"RESPONSABLE_DECLARATION\": \"Nom du responsable signataire\",\n  \"FONCTION_RESPONSABLE\": \"Fonction du signataire\",\n  \"DATE_CERTIFICATION\": \"Date de certification\",\n  \"SIGNATURE\": \"Hash de la signature ├®lectronique\"\n}',1),(2,'DATE_OPERATION,REFERENCE_OPERATION,DEVISE,MONTANT,TAUX_CHANGE,TYPE_OPERATION,SENS_OPERATION,CONTREPARTIE,AGENCE\n\n{{DATE_OPERATION}},{{REFERENCE_OPERATION}},{{DEVISE}},{{MONTANT}},{{TAUX_CHANGE}},{{TYPE_OPERATION}},{{SENS_OPERATION}},{{CONTREPARTIE}},{{AGENCE}}\n','{\n  \"DATE_OPERATION\": \"date_operation\",\n  \"REFERENCE_OPERATION\": \"reference_operation\",\n  \"DEVISE\": \"devise\",\n  \"MONTANT\": \"montant\",\n  \"TAUX_CHANGE\": \"taux_change\",\n  \"TYPE_OPERATION\": \"type_operation\",\n  \"SENS_OPERATION\": \"sens_operation\",\n  \"CONTREPARTIE\": \"contrepartie\",\n  \"AGENCE\": \"agence\"\n}\n',2),(3,'RAPPORT DE CONFORMIT├ë IT & S├ëCURIT├ë ANNUEL\n==========================================\n\n1. INFORMATIONS G├ëN├ëRALES\n-------------------------\nCode du rapport : {{CODE}}\nG├®n├®r├® le : {{DATE_GEN}}\nAuditeur en charge : {{audit_securite}}\nDate de l\'audit : {{date_audit}}\nResponsable de la S├®curit├® (RSSI) : {{responsable_securite}}\n\n2. ├ëVALUATION TECHNIQUE\n-----------------------\nNiveau de conformit├® global : {{niveau_conformite}}%\nNombre d\'incidents majeurs d├®tect├®s : {{incidents_majeurs}}\n\n3. CONTINUIT├ë D\'ACTIVIT├ë\n------------------------\nDate du dernier test PCA/PRA : {{test_pca_date}}\nR├®sultat du test : {{resultat_pca}}\n\n4. RECOMMANDATIONS ET ├ëVOLUTIONS\n--------------------------------\nPlan d\'action d├®taill├® :\n{{plan_action}}\n\n------------------------------------------\nG├®n├®r├® automatiquement\n','',3),(4,'<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<DeclarationBancaire>\n  <Entete>\n    <CodeBanque>{{code_banque}}</CodeBanque>\n    <NomBanque>{{nom_banque}}</NomBanque>\n    <Annee>{{annee}}</Annee>\n    <Trimestre>{{trimestre}}</Trimestre>\n    <PeriodeDebut>{{date_debut}}</PeriodeDebut>\n    <PeriodeFin>{{date_fin}}</PeriodeFin>\n    <Devise>{{devise}}</Devise>\n    <DateGeneration>{{date_generation}}</DateGeneration>\n  </Entete>\n\n  <BilanFinancier>\n    <TotalDepots>{{total_depots}}</TotalDepots>\n    <TotalCredits>{{total_credits}}</TotalCredits>\n    <ResultatNet>{{resultat_net}}</ResultatNet>\n    <FondsPropres>{{fonds_propres}}</FondsPropres>\n    <TotalActifs>{{total_actifs}}</TotalActifs>\n    <TotalPassifs>{{total_passifs}}</TotalPassifs>\n    <LiquiditesDisponibles>{{liquidites_disponibles}}</LiquiditesDisponibles>\n  </BilanFinancier>\n\n  <RatiosPrudentiels>\n    <RatioLiquidite>{{ratio_liquidite}}</RatioLiquidite>\n    <RatioSolvabilite>{{ratio_solvabilite}}</RatioSolvabilite>\n    <RatioLevier>{{ratio_levier}}</RatioLevier>\n    <CouvertureCreances>{{couverture_creances}}</CouvertureCreances>\n  </RatiosPrudentiels>\n\n  <Signature>\n    <ResponsableNom>{{responsable_nom}}</ResponsableNom>\n    <ResponsableFonction>{{responsable_fonction}}</ResponsableFonction>\n    <DateSignature>{{date_signature}}</DateSignature>\n    <StatutDeclaration>{{statut_declaration}}</StatutDeclaration>\n  </Signature>\n</DeclarationBancaire>\n    ','',4);
