  `code` varchar(50) NOT NULL,
  `cree_par` varchar(255) DEFAULT NULL,
  `date_creation` datetime(6) NOT NULL,
  `date_limite` varchar(255) DEFAULT NULL,
  `derniere_modification` datetime(6) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `format` enum('TXT','XML','CSV','JSON','PDF') NOT NULL,
  `frequence` enum('QUOTIDIENNE','JOURNALIERE','HEBDOMADAIRE','MENSUELLE','TRIMESTRIELLE','ANNUELLE') NOT NULL,
  `modifie_par` varchar(255) DEFAULT NULL,
  `nom` varchar(255) NOT NULL,
  `sql_query` text DEFAULT NULL,
  `xsd_content` mediumtext DEFAULT NULL,
  `xsd_file_name` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `UK_pg8nr0b6wnmd3n7euto827e6l` (`code`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
