  <position_nette_tnd>7673400.00</position_nette_tnd>\r\n      <date_valeur>2025-01-31</date_valeur>\r\n    </Ligne>\r\n  </Donnees>\r\n</Declaration>\r\n','2025-01-01',NULL,'2025-01-31','2026-03-10 14:07:06.000000','2026-04-03 22:12:48.000000','rawena',NULL,'declaration_BCT_01_202501.xml','2025-01','SELECT\n    pc.devise_code,\n    pc.devise_libelle,\n    pc.type_position,\n    pc.montant_actifs,\n    pc.montant_passifs,\n    pc.position_nette,\n    pc.taux_change,\n    pc.position_nette_tnd,\n    pc.date_valeur\nFROM position_change pc\nWHERE pc.date_valeur BETWEEN :dateDebut AND :dateFin\nORDER BY pc.date_valeur, pc.devise_code','VALIDEE','ridha_labaoui','declaration_risques_change_taux.xsd',1),(4,NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"no\"?>\r\n<Declaration code=\"BCT_04\" dateDebut=\"2025-01-01\" dateFin=\"2025-01-31\" nombreLignes=\"1\" periode=\"2025-01\">\r\n  <Entete>\r\n    <CodeDeclaration>BCT_04</CodeDeclaration>\r\n    <Periode>2025-01</Periode>\r\n    <DateDebut>2025-01-01</DateDebut>\r\n    <DateFin>2025-01-31</DateFin>\r\n    <NombreLignes>1</NombreLignes>\r\n    <DateGeneration>2026-03-11T09:40:28.815589900</DateGeneration>\r\n  </Entete>\r\n  <Donnees>\r\n    <Ligne>\r\n      <code_banque>WIFAK</code_banque>\r\n      <nom_banque>WIFAK BANK</nom_banque>\r\n      <code_agrement>AGR-2010-014</code_agrement>\r\n      <annee>2025</annee>\r\n      <trimestre>T1</trimestre>\r\n      <devise>TND</devise>\r\n      <periode_debut>2025-01-01</periode_debut>\r\n      <periode_fin>2025-01-31</periode_fin>\r\n      <date_generation>2026-03-11</date_generation>\r\n      <type_declaration>DEFINITIF</type_declaration>\r\n      <total_actifs>1250000.000</total_actifs>\r\n      <creances_clientele>820000.000</creances_clientele>\r\n      <creances_douteuses>45000.000</creances_douteuses>\r\n      <provisions>22000.000</provisions>\r\n      <titres_placement>95000.000</titres_placement>\r\n      <titres_investissement>110000.000</titres_investissement>\r\n      <immobilisations_nettes>68000.000</immobilisations_nettes>\r\n      <autres_actifs>90000.000</autres_actifs>\r\n      <total_passifs>1250000.000</total_passifs>\r\n      <depots_demande>180000.000</depots_demande>\r\n      <depots_epargne>210000.000</depots_epargne>\r\n      <depots_terme>320000.000</depots_terme>\r\n      <total_depots>710000.000</total_depots>\r\n      <emprunts_interbancaires>140000.000</emprunts_interbancaires>\r\n      <emprunts_subordonnes>85000.000</emprunts_subordonnes>\r\n      <autres_passifs>65000.000</autres_passifs>\r\n      <fonds_propres>250000.000</fonds_propres>\r\n      <produit_net_bancaire>32000.000</produit_net_bancaire>\r\n      <charges_exploitation>14000.000</charges_exploitation>\r\n      <dotations_provisions>4500.000</dotations_provisions>\r\n      <resultat_exploitation>13500.000</resultat_exploitation>\r\n      <charges_exceptionnelles>1200.000</charges_exceptionnelles>\r\n      <resultat_net>12300.000</resultat_net>\r\n      <ratio_cet1>12.500</ratio_cet1>\r\n      <ratio_tier1>13.800</ratio_tier1>\r\n      <ratio_total_capital>15.200</ratio_total_capital>\r\n      <ratio_levier>4.700</ratio_levier>\r\n      <couverture_creances>82.300</couverture_creances>\r\n      <ratio_transformation>115.600</ratio_transformation>\r\n      <conforme_basel>true</conforme_basel>\r\n      <total_credits>820000.000</total_credits>\r\n      <credits_particuliers>245000.000</credits_particuliers>\r\n      <credits_pme>310000.000</credits_pme>\r\n      <credits_grandes_ent>180000.000</credits_grandes_ent>\r\n      <credits_immobiliers>62000.000</credits_immobiliers>\r\n      <credits_consommation>23000.000</credits_consommation>\r\n      <nouveaux_credits>95000.000</nouveaux_credits>\r\n      <remboursements>41000.000</remboursements>\r\n      <creances_classe1>15000.000</creances_classe1>\r\n      <creances_classe2>18000.000</creances_classe2>\r\n      <creances_classe3>8000.000</creances_classe3>\r\n      <creances_classe4>4000.000</creances_classe4>\r\n      <total_creances_classees>45000.000</total_creances_classees>\r\n      <ratio_lcr>128.500</ratio_lcr>\r\n      <ratio_nsfr>112.300</ratio_nsfr>\r\n      <reserves_obligatoires>35000.000</reserves_obligatoires>\r\n      <excedent_reserves>3500.000</excedent_reserves>\r\n      <liquidites_disponibles>95000.000</liquidites_disponibles>\r\n      <actifs_liquides_hq>85000.000</actifs_liquides_hq>\r\n      <sorties_nettes>74000.000</sorties_nettes>\r\n      <responsable_nom>Mohamed Ali Ben Salah</responsable_nom>\r\n      <responsable_fonction>Directeur Financier</responsable_fonction>\r\n      <responsable_email>mabensalah@wifakbank.tn</responsable_email>\r\n      <date_signature>2025-04-28</date_signature>\r\n      <statut>DEFINITIF</statut>\r\n      <numero_reference>BCT04-2025-T1-WIFAK</numero_reference>\r\n    </Ligne>\r\n  </Donnees>\r\n</Declaration>\r\n','2025-01-01',NULL,'2025-01-31','2026-03-11 08:40:28.000000','2026-04-03 21:37:30.000000','rawena',NULL,'declaration_BCT_04_202501.xml','2025-01','SELECT\n    b.code_banque,\n    b.nom_banque,\n    b.code_agrement,\n    bi.annee,\n    bi.trimestre,\n    b.devise,\n    :dateDebut                AS periode_debut,\n    :dateFin                  AS periode_fin,\n    CURRENT_DATE              AS date_generation,\n    \'DEFINITIF\'               AS type_declaration,\n\n    bi.total_actifs,\n    bi.creances_clientele,\n    bi.creances_douteuses,\n    bi.provisions,\n    bi.titres_placement,\n    bi.titres_investissement,\n    bi.immobilisations_nettes,\n    bi.autres_actifs,\n    bi.total_passifs,\n    bi.depots_demande,\n    bi.depots_epargne,\n    bi.depots_terme,\n    bi.total_depots,\n    bi.emprunts_interbancaires,\n    bi.emprunts_subordonnes,\n    bi.autres_passifs,\n    bi.fonds_propres,\n\n    cr.produit_net_bancaire,\n    cr.charges_exploitation,\n    cr.dotations_provisions,\n    cr.resultat_exploitation,\n    cr.charges_exceptionnelles,\n    cr.resultat_net,\n\n    rp.ratio_cet1,\n    rp.ratio_tier1,\n    rp.ratio_total_capital,\n    rp.ratio_levier,\n    rp.couverture_creances,\n    rp.ratio_transformation,\n    CASE\n        WHEN rp.ratio_cet1 >= 4.5\n         AND rp.ratio_tier1 >= 6.0\n         AND rp.ratio_total_capital >= 8.0\n        THEN \'true\' ELSE \'false\'\n    END AS conforme_basel,\n\n    c.total_credits,\n    c.credits_particuliers,\n    c.credits_pme,\n    c.credits_grandes_ent,\n    c.credits_immobiliers,\n    c.credits_consommation,\n    c.nouveaux_credits,\n    c.remboursements,\n    c.creances_classe1,\n    c.creances_classe2,\n    c.creances_classe3,\n    c.creances_classe4,\n    (c.creances_classe1 + c.creances_classe2 +\n     c.creances_classe3 + c.creances_classe4) AS total_creances_classees,\n\n    liq.ratio_lcr,\n    liq.ratio_nsfr,\n    liq.reserves_obligatoires,\n    (liq.reserves_constituees - liq.reserves_obligatoires) AS excedent_reserves,\n    liq.liquidites_disponibles,\n    liq.actifs_liquides_hq,\n    liq.sorties_nettes,\n\n    sd.responsable_nom,\n    sd.responsable_fonction,\n    sd.responsable_email,\n    sd.date_signature,\n    sd.statut,\n    sd.numero_reference\n\nFROM banque b\nJOIN bilan bi\n    ON bi.banque_id = b.id\n   AND bi.annee     = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND bi.trimestre = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                          WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                          WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                          WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                          ELSE \'T4\' END\n\nJOIN compte_resultat cr\n    ON cr.banque_id = b.id\n   AND cr.annee     = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND cr.trimestre = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                          WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                          WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                          WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                          ELSE \'T4\' END\n\nJOIN ratios_prudentiels rp\n    ON rp.banque_id = b.id\n   AND rp.annee     = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND rp.trimestre = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                          WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                          WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                          WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                          ELSE \'T4\' END\n\nJOIN credits c\n    ON c.banque_id  = b.id\n   AND c.annee      = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND c.trimestre  = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                          WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                          WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                          WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                          ELSE \'T4\' END\n\nJOIN liquidite liq\n    ON liq.banque_id = b.id\n   AND liq.annee     = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND liq.trimestre = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                           WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                           WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                           WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                           ELSE \'T4\' END\n\nJOIN signature_declaration sd\n    ON sd.banque_id = b.id\n   AND sd.annee     = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND sd.trimestre = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                          WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                          WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                          WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                          ELSE \'T4\' END','VALIDEE','ridha_labaoui','BCT_04_declaration_trimestrielle.xsd',4),(5,NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"no\"?>\r\n<Declaration code=\"BCT_03\" dateDebut=\"2026-03-01\" dateFin=\"2026-03-31\" nombreLignes=\"1\" periode=\"2026-03\">\r\n  <Entete>\r\n    <CodeDeclaration>BCT_03</CodeDeclaration>\r\n    <Periode>2026-03</Periode>\r\n    <DateDebut>2026-03-01</DateDebut>\r\n    <DateFin>2026-03-31</DateFin>\r\n    <NombreLignes>1</NombreLignes>\r\n    <DateGeneration>2026-03-11T15:12:31.972594700</DateGeneration>\r\n  </Entete>\r\n  <Donnees>\r\n    <Ligne>\r\n      <code_banque>WIFAK</code_banque>\r\n      <nom_banque>WIFAK BANK</nom_banque>\r\n      <code_agrement>AGR-2010-014</code_agrement>\r\n      <periode>2026-03</periode>\r\n      <date_debut>2026-03-01</date_debut>\r\n      <date_fin>2026-03-31</date_fin>\r\n      <date_generation>2026-03-11</date_generation>\r\n      <type_declaration>DEFINITIF</type_declaration>\r\n      <niveau_conformite>CONFORME</niveau_conformite>\r\n      <nb_serveurs_total>85</nb_serveurs_total>\r\n      <nb_serveurs_actifs>80</nb_serveurs_actifs>\r\n      <nb_applications_critiques>12</nb_applications_critiques>\r\n      <nb_bases_de_data>8</nb_bases_de_data>\r\n      <taux_disponibilite_systemes>99.720</taux_disponibilite_systemes>\r\n      <taux_disponibilite_cible>99.900</taux_disponibilite_cible>\r\n      <hebergement_cloud>true</hebergement_cloud>\r\n      <fournisseur_cloud>AWS Bahrain</fournisseur_cloud>\r\n      <derniere_maj>2026-02-15</derniere_maj>\r\n      <nb_vulnerabilites_critiques>3</nb_vulnerabilites_critiques>\r\n      <nb_vulnerabilites_hautes>11</nb_vulnerabilites_hautes>\r\n      <nb_vulnerabilites_corrigees>12</nb_vulnerabilites_corrigees>\r\n      <taux_correction>85.700</taux_correction>\r\n      <antivirus_actif>true</antivirus_actif>\r\n      <firewall_actif>true</firewall_actif>\r\n      <chiffrement_donnees>true</chiffrement_donnees>\r\n      <mfa_actif>true</mfa_actif>\r\n      <dernier_test_penetration>2026-02-20</dernier_test_penetration>\r\n      <resultat_test_penetration>REUSSI</resultat_test_penetration>\r\n      <certification_iso27001>true</certification_iso27001>\r\n      <date_expiration_certif>2027-06-30</date_expiration_certif>\r\n      <nb_incidents_totaux>14</nb_incidents_totaux>\r\n      <nb_incidents_critiques>2</nb_incidents_critiques>\r\n      <nb_incidents_resolus>12</nb_incidents_resolus>\r\n      <nb_incidents_en_cours>2</nb_incidents_en_cours>\r\n      <delai_moyen_resolution_heures>4.50</delai_moyen_resolution_heures>\r\n      <nb_violations_donnees>0</nb_violations_donnees>\r\n      <nb_attaques_cyber>27</nb_attaques_cyber>\r\n      <nb_attaques_bloquees>25</nb_attaques_bloquees>\r\n      <procedure_incident_documentee>true</procedure_incident_documentee>\r\n      <plan_continuite_existe>true</plan_continuite_existe>\r\n      <date_dernier_test>2026-01-15</date_dernier_test>\r\n      <resultat_dernier_test>REUSSI</resultat_dernier_test>\r\n      <site_secours_dispo>true</site_secours_dispo>\r\n      <delai_basculement_minutes>30</delai_basculement_minutes>\r\n      <rpo_heures>1.00</rpo_heures>\r\n      <rto_heures>2.00</rto_heures>\r\n      <frequence_sauvegardes>QUOTIDIENNE</frequence_sauvegardes>\r\n      <dernier_test_restauration>2026-02-10</dernier_test_restauration>\r\n      <politique_confidentialite>true</politique_confidentialite>\r\n      <responsable_protection_donnees>Sami Trabelsi</responsable_protection_donnees>\r\n      <nb_demandes_acces>45</nb_demandes_acces>\r\n      <nb_demandes_traitees>44</nb_demandes_traitees>\r\n      <nb_violations_signalees>0</nb_violations_signalees>\r\n      <consentement_clients_gere>true</consentement_clients_gere>\r\n      <registre_traitements_a_jour>true</registre_traitements_a_jour>\r\n      <formation_sensibilisation>true</formation_sensibilisation>\r\n      <nb_employes_formes>230</nb_employes_formes>\r\n      <nb_audits_realises>3</nb_audits_realises>\r\n      <nb_non_conformites_majeures>1</nb_non_conformites_majeures>\r\n      <nb_non_conformites_mineurs>4</nb_non_conformites_mineurs>\r\n      <nb_actions_correctives_ouvertes>2</nb_actions_correctives_ouvertes>\r\n      <nb_actions_correctives_closes>8</nb_actions_correctives_closes>\r\n      <date_dernier_audit_interne>2026-03-20</date_dernier_audit_interne>\r\n      <date_dernier_audit_externe>2026-01-10</date_dernier_audit_externe>\r\n      <score_conformite_global>91.500</score_conformite_global>\r\n      <responsable_nom>Nour El Houda Mansour</responsable_nom>\r\n      <responsable_fonction>Directeur des Syst├¿mes d\'Information</responsable_fonction>\r\n      <responsable_email>nmansour@wifakbank.tn</responsable_email>\r\n      <rssi>Karim Bouzid</rssi>\r\n      <date_signature>2026-03-31</date_signature>\r\n      <statut>DEFINITIF</statut>\r\n      <numero_reference>BCT05-2026-03-WIFAK</numero_reference>\r\n      <observations>D├®claration mensuelle de conformit├® IT pour mars 2026. Score global : 91.5%</observations>\r\n    </Ligne>\r\n  </Donnees>\r\n</Declaration>\r\n','2026-03-01',NULL,'2026-03-31','2026-03-11 14:12:32.000000','2026-03-26 20:47:48.000000','rawena',NULL,'declaration_BCT_03_202603.xml','2026-03','\nSELECT\n    -- ENT├èTE\n    b.code_banque,\n    b.nom_banque,\n    b.code_agrement,\n    inf.periode,\n    inf.date_debut,\n    inf.date_fin,\n    CURRENT_DATE                AS date_generation,\n    \'DEFINITIF\'                 AS type_declaration,\n    CASE\n        WHEN aud.score_conformite_global >= 90 THEN \'CONFORME\'\n        WHEN aud.score_conformite_global >= 70 THEN \'PARTIELLEMENT_CONFORME\'\n        ELSE \'NON_CONFORME\'\n    END                         AS niveau_conformite,\n\n    -- INFRASTRUCTURE IT\n    inf.nb_serveurs_total,\n    inf.nb_serveurs_actifs,\n    inf.nb_applications_critiques,\n    inf.nb_bases_de_data,\n    inf.taux_disponibilite_systemes,\n    inf.taux_disponibilite_cible,\n    inf.hebergement_cloud,\n    inf.fournisseur_cloud,\n    inf.derniere_maj,\n\n    -- S├ëCURIT├ë\n    sec.nb_vulnerabilites_critiques,\n    sec.nb_vulnerabilites_hautes,\n    sec.nb_vulnerabilites_corrigees,\n    sec.taux_correction,\n    sec.antivirus_actif,\n    sec.firewall_actif,\n    sec.chiffrement_donnees,\n    sec.mfa_actif,\n    sec.dernier_test_penetration,\n    sec.resultat_test_penetration,\n    sec.certification_iso27001,\n    sec.date_expiration_certif,\n\n    -- INCIDENTS\n    inc.nb_incidents_totaux,\n    inc.nb_incidents_critiques,\n    inc.nb_incidents_resolus,\n    inc.nb_incidents_en_cours,\n    inc.delai_moyen_resolution_heures,\n    inc.nb_violations_donnees,\n    inc.nb_attaques_cyber,\n    inc.nb_attaques_bloquees,\n    inc.procedure_incident_documentee,\n\n    -- CONTINUIT├ë\n    con.plan_continuite_existe,\n    con.date_dernier_test,\n    con.resultat_dernier_test,\n    con.site_secours_dispo,\n    con.delai_basculement_minutes,\n    con.rpo_heures,\n    con.rto_heures,\n    con.frequence_sauvegardes,\n    con.dernier_test_restauration,\n\n    -- RGPD\n    rgpd.politique_confidentialite,\n    rgpd.responsable_protection_donnees,\n    rgpd.nb_demandes_acces,\n    rgpd.nb_demandes_traitees,\n    rgpd.nb_violations_signalees,\n    rgpd.consentement_clients_gere,\n    rgpd.registre_traitements_a_jour,\n    rgpd.formation_sensibilisation,\n    rgpd.nb_employes_formes,\n\n    -- AUDITS\n    aud.nb_audits_realises,\n    aud.nb_non_conformites_majeures,\n    aud.nb_non_conformites_mineurs,\n    aud.nb_actions_correctives_ouvertes,\n    aud.nb_actions_correctives_closes,\n    aud.date_dernier_audit_interne,\n    aud.date_dernier_audit_externe,\n    aud.score_conformite_global,\n\n    -- SIGNATURE\n    sig.responsable_nom,\n    sig.responsable_fonction,\n    sig.responsable_email,\n    sig.rssi,\n    sig.date_signature,\n    sig.statut,\n    sig.numero_reference,\n    sig.observations\n\nFROM banque b\nJOIN it_infrastructure inf  ON inf.banque_id = b.id\n    AND inf.date_debut >= :dateDebut\n    AND inf.date_fin   <= :dateFin\nJOIN it_securite sec        ON sec.banque_id = b.id AND sec.periode = inf.periode\nJOIN it_incidents inc       ON inc.banque_id = b.id AND inc.periode = inf.periode\nJOIN it_continuite con      ON con.banque_id = b.id AND con.periode = inf.periode\nJOIN it_rgpd rgpd           ON rgpd.banque_id = b.id AND rgpd.periode = inf.periode\nJOIN it_audits aud          ON aud.banque_id = b.id AND aud.periode = inf.periode\nJOIN it_signature sig       ON sig.banque_id = b.id AND sig.periode = inf.periode\n\n\n','VALIDEE','ridha_labaoui','BCT_05_conformite_it_securite.xsd',3),(6,'D├®claration quotidienne des op├®rations de change  : champ invalide','<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"no\"?>\r\n<Declaration code=\"BCT_002\" dateDebut=\"2025-01-01\" dateFin=\"2025-01-31\" nombreLignes=\"3\" periode=\"2025-01\">\r\n  <Entete>\r\n    <CodeDeclaration>BCT_002</CodeDeclaration>\r\n    <Periode>2025-01</Periode>\r\n    <DateDebut>2025-01-01</DateDebut>\r\n    <DateFin>2025-01-31</DateFin>\r\n    <NombreLignes>3</NombreLignes>\r\n    <DateGeneration>2026-03-11T16:24:36.375793600</DateGeneration>\r\n  </Entete>\r\n  <Donnees>\r\n    <Ligne>\r\n      <id>1</id>\r\n      <nom_client>Ahmed Ben Ali</nom_client>\r\n      <montant_impaye>1200.500</montant_impaye>\r\n      <date_impaye>2025-01-16</date_impaye>\r\n    </Ligne>\r\n    <Ligne>\r\n      <id>2</id>\r\n      <nom_client>Sonia Trabelsi</nom_client>\r\n      <montant_impaye>850.000</montant_impaye>\r\n      <date_impaye>2025-01-22</date_impaye>\r\n    </Ligne>\r\n    <Ligne>\r\n      <id>3</id>\r\n      <nom_client>Mohamed Gharbi</nom_client>\r\n      <montant_impaye>3200.750</montant_impaye>\r\n      <date_impaye>2025-01-11</date_impaye>\r\n    </Ligne>\r\n  </Donnees>\r\n</Declaration>\r\n','2025-01-01',NULL,'2025-01-31','2026-03-11 15:24:36.000000','2026-04-03 21:29:05.000000','rawena',NULL,'declaration_BCT_002_202501.xml','2025-01','SELECT id, nom_client, montant_impaye, date_impaye FROM impayes WHERE date_impaye BETWEEN :dateDebut AND :dateFin','VALIDEE','ridha_labaoui','declaration_impayes_simple.xsd',2),(7,'Type\nD├®claration quotidienne des op├®rations de change','numero_client;nom_client;numero_compte;montant_impaye;montant_penalite\nCLI001;Ahmed Ben Ali;TN001234;1200.500;0.000\nCLI002;Sonia Trabelsi;TN005678;850.000;0.000\nCLI003;Mohamed Gharbi;TN009012;3200.750;0.000\n','2025-03-01',NULL,'2025-03-31','2026-03-11 15:52:08.000000','2026-04-03 21:42:08.000000','rawena',NULL,'declaration_BCT_002_202503.csv','2025-03','SELECT numero_client, nom_client, numero_compte, montant_impaye, montant_penalite\nFROM impayes \n','VALIDEE','ridha_labaoui','declaration_impayes_simple.xsd',2),(8,NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"no\"?>\r\n<Declaration code=\"BCT_04\" dateDebut=\"2025-01-01\" dateFin=\"2025-01-31\" nombreLignes=\"1\" periode=\"2025-01\">\r\n  <Entete>\r\n    <CodeDeclaration>BCT_04</CodeDeclaration>\r\n    <Periode>2025-01</Periode>\r\n    <DateDebut>2025-01-01</DateDebut>\r\n    <DateFin>2025-01-31</DateFin>\r\n    <NombreLignes>1</NombreLignes>\r\n    <DateGeneration>2026-03-11T16:54:11.485523</DateGeneration>\r\n  </Entete>\r\n  <Donnees>\r\n    <Ligne>\r\n      <code_banque>WIFAK</code_banque>\r\n      <nom_banque>WIFAK BANK</nom_banque>\r\n      <code_agrement>AGR-2010-014</code_agrement>\r\n      <annee>2025</annee>\r\n      <trimestre>T1</trimestre>\r\n      <devise>TND</devise>\r\n      <periode_debut>2025-01-01</periode_debut>\r\n      <periode_fin>2025-01-31</periode_fin>\r\n      <date_generation>2026-03-11</date_generation>\r\n      <type_declaration>DEFINITIF</type_declaration>\r\n      <total_actifs>1250000.000</total_actifs>\r\n      <creances_clientele>820000.000</creances_clientele>\r\n      <creances_douteuses>45000.000</creances_douteuses>\r\n      <provisions>22000.000</provisions>\r\n      <titres_placement>95000.000</titres_placement>\r\n      <titres_investissement>110000.000</titres_investissement>\r\n      <immobilisations_nettes>68000.000</immobilisations_nettes>\r\n      <autres_actifs>90000.000</autres_actifs>\r\n      <total_passifs>1250000.000</total_passifs>\r\n      <depots_demande>180000.000</depots_demande>\r\n      <depots_epargne>210000.000</depots_epargne>\r\n      <depots_terme>320000.000</depots_terme>\r\n      <total_depots>710000.000</total_depots>\r\n      <emprunts_interbancaires>140000.000</emprunts_interbancaires>\r\n      <emprunts_subordonnes>85000.000</emprunts_subordonnes>\r\n      <autres_passifs>65000.000</autres_passifs>\r\n      <fonds_propres>250000.000</fonds_propres>\r\n      <produit_net_bancaire>32000.000</produit_net_bancaire>\r\n      <charges_exploitation>14000.000</charges_exploitation>\r\n      <dotations_provisions>4500.000</dotations_provisions>\r\n      <resultat_exploitation>13500.000</resultat_exploitation>\r\n      <charges_exceptionnelles>1200.000</charges_exceptionnelles>\r\n      <resultat_net>12300.000</resultat_net>\r\n      <ratio_cet1>12.500</ratio_cet1>\r\n      <ratio_tier1>13.800</ratio_tier1>\r\n      <ratio_total_capital>15.200</ratio_total_capital>\r\n      <ratio_levier>4.700</ratio_levier>\r\n      <couverture_creances>82.300</couverture_creances>\r\n      <ratio_transformation>115.600</ratio_transformation>\r\n      <conforme_basel>true</conforme_basel>\r\n      <total_credits>820000.000</total_credits>\r\n      <credits_particuliers>245000.000</credits_particuliers>\r\n      <credits_pme>310000.000</credits_pme>\r\n      <credits_grandes_ent>180000.000</credits_grandes_ent>\r\n      <credits_immobiliers>62000.000</credits_immobiliers>\r\n      <credits_consommation>23000.000</credits_consommation>\r\n      <nouveaux_credits>95000.000</nouveaux_credits>\r\n      <remboursements>41000.000</remboursements>\r\n      <creances_classe1>15000.000</creances_classe1>\r\n      <creances_classe2>18000.000</creances_classe2>\r\n      <creances_classe3>8000.000</creances_classe3>\r\n      <creances_classe4>4000.000</creances_classe4>\r\n      <total_creances_classees>45000.000</total_creances_classees>\r\n      <ratio_lcr>128.500</ratio_lcr>\r\n      <ratio_nsfr>112.300</ratio_nsfr>\r\n      <reserves_obligatoires>35000.000</reserves_obligatoires>\r\n      <excedent_reserves>3500.000</excedent_reserves>\r\n      <liquidites_disponibles>95000.000</liquidites_disponibles>\r\n      <actifs_liquides_hq>85000.000</actifs_liquides_hq>\r\n      <sorties_nettes>74000.000</sorties_nettes>\r\n      <responsable_nom>Mohamed Ali Ben Salah</responsable_nom>\r\n      <responsable_fonction>Directeur Financier</responsable_fonction>\r\n      <responsable_email>mabensalah@wifakbank.tn</responsable_email>\r\n      <date_signature>2025-04-28</date_signature>\r\n      <statut>DEFINITIF</statut>\r\n      <numero_reference>BCT04-2025-T1-WIFAK</numero_reference>\r\n    </Ligne>\r\n  </Donnees>\r\n</Declaration>\r\n','2025-01-01',NULL,'2025-01-31','2026-03-11 15:54:11.000000','2026-03-26 17:14:34.000000','rawena',NULL,'declaration_BCT_04_202501.xml','2025-01','SELECT\n    b.code_banque,\n    b.nom_banque,\n    b.code_agrement,\n    bi.annee,\n    bi.trimestre,\n    b.devise,\n    :dateDebut                AS periode_debut,\n    :dateFin                  AS periode_fin,\n    CURRENT_DATE              AS date_generation,\n    \'DEFINITIF\'               AS type_declaration,\n\n    bi.total_actifs,\n    bi.creances_clientele,\n    bi.creances_douteuses,\n    bi.provisions,\n    bi.titres_placement,\n    bi.titres_investissement,\n    bi.immobilisations_nettes,\n    bi.autres_actifs,\n    bi.total_passifs,\n    bi.depots_demande,\n    bi.depots_epargne,\n    bi.depots_terme,\n    bi.total_depots,\n    bi.emprunts_interbancaires,\n    bi.emprunts_subordonnes,\n    bi.autres_passifs,\n    bi.fonds_propres,\n\n    cr.produit_net_bancaire,\n    cr.charges_exploitation,\n    cr.dotations_provisions,\n    cr.resultat_exploitation,\n    cr.charges_exceptionnelles,\n    cr.resultat_net,\n\n    rp.ratio_cet1,\n    rp.ratio_tier1,\n    rp.ratio_total_capital,\n    rp.ratio_levier,\n    rp.couverture_creances,\n    rp.ratio_transformation,\n    CASE\n        WHEN rp.ratio_cet1 >= 4.5\n         AND rp.ratio_tier1 >= 6.0\n         AND rp.ratio_total_capital >= 8.0\n        THEN \'true\' ELSE \'false\'\n    END AS conforme_basel,\n\n    c.total_credits,\n    c.credits_particuliers,\n    c.credits_pme,\n    c.credits_grandes_ent,\n    c.credits_immobiliers,\n    c.credits_consommation,\n    c.nouveaux_credits,\n    c.remboursements,\n    c.creances_classe1,\n    c.creances_classe2,\n    c.creances_classe3,\n    c.creances_classe4,\n    (c.creances_classe1 + c.creances_classe2 +\n     c.creances_classe3 + c.creances_classe4) AS total_creances_classees,\n\n    liq.ratio_lcr,\n    liq.ratio_nsfr,\n    liq.reserves_obligatoires,\n    (liq.reserves_constituees - liq.reserves_obligatoires) AS excedent_reserves,\n    liq.liquidites_disponibles,\n    liq.actifs_liquides_hq,\n    liq.sorties_nettes,\n\n    sd.responsable_nom,\n    sd.responsable_fonction,\n    sd.responsable_email,\n    sd.date_signature,\n    sd.statut,\n    sd.numero_reference\n\nFROM banque b\nJOIN bilan bi\n    ON bi.banque_id = b.id\n   AND bi.annee     = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND bi.trimestre = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                          WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                          WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                          WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                          ELSE \'T4\' END\n\nJOIN compte_resultat cr\n    ON cr.banque_id = b.id\n   AND cr.annee     = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND cr.trimestre = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                          WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                          WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                          WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                          ELSE \'T4\' END\n\nJOIN ratios_prudentiels rp\n    ON rp.banque_id = b.id\n   AND rp.annee     = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND rp.trimestre = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                          WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                          WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                          WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                          ELSE \'T4\' END\n\nJOIN credits c\n    ON c.banque_id  = b.id\n   AND c.annee      = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND c.trimestre  = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                          WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                          WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                          WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                          ELSE \'T4\' END\n\nJOIN liquidite liq\n    ON liq.banque_id = b.id\n   AND liq.annee     = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND liq.trimestre = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                           WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                           WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                           WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                           ELSE \'T4\' END\n\nJOIN signature_declaration sd\n    ON sd.banque_id = b.id\n   AND sd.annee     = EXTRACT(YEAR FROM CAST(:dateDebut AS DATE))\n   AND sd.trimestre = CASE EXTRACT(MONTH FROM CAST(:dateDebut AS DATE))\n                          WHEN 1 THEN \'T1\' WHEN 2 THEN \'T1\' WHEN 3 THEN \'T1\'\n                          WHEN 4 THEN \'T2\' WHEN 5 THEN \'T2\' WHEN 6 THEN \'T2\'\n                          WHEN 7 THEN \'T3\' WHEN 8 THEN \'T3\' WHEN 9 THEN \'T3\'\n                          ELSE \'T4\' END','VALIDEE','ridha_labaoui','BCT_04_declaration_trimestrielle.xsd',4),(9,NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"no\"?>\r\n<Declaration code=\"BCT_04\" dateDebut=\"2026-01-01\" dateFin=\"2026-01-31\" nombreLignes=\"0\" periode=\"2026-01\">\r\n  <Entete>\r\n    <CodeDeclaration>BCT_04</CodeDeclaration>\r\n    <Periode>2026-01</Periode>\r\n    <DateDebut>2026-01-01</DateDebut>\r\n    <DateFin>2026-01-31</DateFin>\r\n    <NombreLignes>0</NombreLignes>\r\n    <DateGeneration>2026-03-31T13:34:44.482482500</DateGeneration>\r\n  </Entete>\r\n  <Donnees/>\r\n</Declaration>\r\n','2026-01-01',NULL,'2026-01-31','2026-03-31 12:34:44.000000','2026-03-31 16:35:47.000000','rawena',NULL,'declaration_BCT_04_202601.xml','2026-01','SELECT\n    d.id,\n    d.nom_fichier,\n    d.statut,\n    d.periode,\n    d.date_debut,\n    d.date_fin,\n    d.date_envoi,\n    d.date_generation,\n    d.genere_par,\n    dt.code,\n    dt.nom,\n    dt.format,\n    dt.frequence\nFROM declarations d\nJOIN declaration_types dt ON dt.id = d.declaration_type_id\nWHERE d.date_debut >= :dateDebut\n  AND d.date_fin <= :dateFin\nORDER BY d.date_generation DESC','VALIDEE','ridha_labaoui','declaration_trimestrielle_bancaire.xsd',4),(10,'D├®claration Trimestrielle des Op├®rations Bancaires','<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"no\"?>\r\n<Declaration code=\"BCT_04\" dateDebut=\"2026-08-01\" dateFin=\"2026-08-31\" nombreLignes=\"0\" periode=\"2026-08\">\r\n  <Entete>\r\n    <CodeDeclaration>BCT_04</CodeDeclaration>\r\n    <Periode>2026-08</Periode>\r\n    <DateDebut>2026-08-01</DateDebut>\r\n    <DateFin>2026-08-31</DateFin>\r\n    <NombreLignes>0</NombreLignes>\r\n    <DateGeneration>2026-03-31T17:34:32.511632700</DateGeneration>\r\n  </Entete>\r\n  <Donnees/>\r\n</Declaration>\r\n','20